mapper.select:
SELECT *
FROM file_asset
WHERE ref_type = #{refType}
  AND ref_id = #{refId}
ORDER BY id

mapper.update:
UPDATE file_asset
   SET ref_type = #{refType},
       ref_id = #{refId}
 WHERE id = #{id}

UPDATE file_asset
   SET ref_type = #{refType},
       ref_id = #{refId}
 WHERE id = #{id}
   AND owner_user_id = #{ownerUserId}
   AND ref_id IS NULL

   AND kind = #{expectedKind}

mapper.delete:
DELETE FROM file_asset
 WHERE id = #{id}
   AND owner_user_id = #{ownerUserId}
   AND ref_type IS NULL
   AND ref_id IS NULL

DELETE FROM file_asset
 WHERE id = #{id}
   AND owner_user_id = #{ownerUserId}
   AND kind = #{expectedKind}
   AND ref_type = #{refType}
   AND ref_id = #{refId}
